const input = $input.first().json;

const parsed = {
  alert_id: input['Alert ID'] || `test_${Date.now()}`,
  ticket_number: input['Ticket Number'] || '',
  member_codes_raw: input['Station Code(s)'] || '',
  issue_type: input['Issue Type'] || '',
  states_raw: input['State'] || '',
  customer_name: input['Customer Name'] || '',
  notes: input['Additional Notes'] || '',
  source: 'manual_test',
  received_at: new Date().toISOString(),
  email_message_id: `test_${Date.now()}`,
  original_subject: `DPS - Department Alert System Result #${input['Alert ID']}`,
  original_body: 'Test input - no original email body'
};

parsed.member_codes = parsed.member_codes_raw ? parsed.member_codes_raw.split(/[,;\/\s]+/).map(c => c.trim().toUpperCase()).filter(c => c.length > 0 && /^[A-Z0-9]+$/.test(c)) : [];
parsed.states = parsed.states_raw ? [parsed.states_raw] : [];

const normalizedCodes = (parsed.member_codes || []).slice().sort().join(',');
const keySource = `${parsed.alert_id}|${parsed.ticket_number}|${normalizedCodes}`;
parsed.idempotency_key = keySource.split('').reduce((a,b) => ((a << 5) - a + b.charCodeAt(0)) | 0, 0).toString(16);
parsed.notes_preview = (parsed.notes || '').substring(0, 200);

return [{ json: parsed }];

const items = $input.all();
const explodedItems = $('Explode Codes').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const lookup = items[i].json;
  const exploded = explodedItems[i]?.json || explodedItems[0].json;
  const stationCode = exploded.station_code;
  const root = exploded.root;
  const hasResult = lookup && lookup.rep_email;

  results.push({
    json: {
      station_code: stationCode,
      found: hasResult,
      rep_email: lookup?.rep_email || null,
      rep_name: lookup?.rep_name || null,
      root: root
    }
  });
}

return results;

const items = $input.all();
const root = items[0].json.root;
const repMap = new Map();
const matchedCodes = [];
const unmatchedCodes = [];

for (const item of items) {
  const code = item.json.station_code;
  if (item.json.found && item.json.rep_email) {
    matchedCodes.push(code);
    const emailKey = item.json.rep_email.toLowerCase();
    if (!repMap.has(emailKey)) {
      repMap.set(emailKey, { rep_email: item.json.rep_email, rep_name: item.json.rep_name || 'Member Rep', station_codes: [] });
    }
    repMap.get(emailKey).station_codes.push(code);
  } else {
    unmatchedCodes.push(code);
  }
}

const recipients = Array.from(repMap.values());

return [{
  json: {
    ...root,
    routing: {
      recipients,
      matched_codes: matchedCodes,
      unmatched_codes: unmatchedCodes,
      has_exceptions: unmatchedCodes.length > 0,
      all_unmatched: recipients.length === 0
    }
  }
}];

const data = $input.first().json;
const notes = (data.notes || '').toLowerCase();
const issueType = (data.issue_type || '').toLowerCase();
const states = (data.states || []).map(s => s.toLowerCase());
const isCA = states.some(s => s.includes('california') || s === 'ca');
const isNV = states.some(s => s.includes('nevada') || s === 'nv');
const isNoResponse = issueType.includes('no response') || notes.includes('no response') || notes.includes('non-response');
const isManuallyAdded = issueType.includes('manually added') || issueType.includes('manual add');
const isContactIssue = notes.includes('contact') || notes.includes('wrong number') || notes.includes('wrong email') || issueType.includes('contact');

const templates = [
  {
    id: 'no_response_ca',
    match: () => isCA && isNoResponse,
    subject: 'No Response Alert: Ticket #{{ticket_number}} - {{station_codes}}',
    body: '{{rep_name}}, please review the form below and reach out to the customer listed to resolve the issue.\n\nPlease monitor the tickets that require Electronic Positive Responses within the Damage Prevention Portal (DPP) as required by California Code 4216 (https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=GOV&division=5.&title=1.&part=&chapter=3.1.&article=2).\n\n• How to use Electronic Positive Response - https://www.youtube.com/watch?v=c1b6HlX-fx4\n\nThank you,'
  },
  {
    id: 'no_response_nv',
    match: () => isNV && isNoResponse,
    subject: 'No Response Alert: Ticket #{{ticket_number}} - {{station_codes}}',
    body: '{{rep_name}}, please review the form below and reach out to the customer listed to resolve the issue.\n\nPlease monitor the tickets that require Electronic Positive Responses within the Damage Prevention Portal (DPP) as required by NRS 455.\n\n• How to use Electronic Positive Response - https://www.youtube.com/watch?v=c1b6HlX-fx4\n\nThank you,'
  },
  {
    id: 'no_response_generic',
    match: () => isNoResponse,
    subject: 'No Response Alert: Ticket #{{ticket_number}} - {{station_codes}}',
    body: '{{rep_name}}, please review the form below and reach out to the customer listed to resolve the issue.\n\nPlease monitor the tickets that require Electronic Positive Responses within the Damage Prevention Portal (DPP).\n\n• How to use Electronic Positive Response - https://www.youtube.com/watch?v=c1b6HlX-fx4\n\nThank you,'
  },
  {
    id: 'contact_info_issue',
    match: () => isContactIssue,
    subject: 'Contact Info Issue: Ticket #{{ticket_number}} - {{station_codes}}',
    body: '{{rep_name}}, please review the email below from one of our agents for reference and reach out to the excavator on the ticket to resolve the issue.\n\nIf you need to update your Member Contact information within the Damage Prevention Portal, please use the link below to sign in. Then navigate to the station details for your station code (Settings > OneCallAccess).\n\nNV DPP Login Page - https://appsnv.undergroundservicealert.org/pcadmin/Account/Login\nCA DPP Login Page - https://appsca.undergroundservicealert.org/pcadmin/Account/Login?returnUrl=%2Fpcadmin%2FOperations - The Damage Prevention Portal is where you can manage your mapping, contact info, and ticket delivery.\n\nContact Information can be found under Settings - OneCallAccess then clicking on your Station Code.\nThe Member Contact is displayed on each ticket available for the excavator.\nThe Member IT contact is not displayed on the ticket and is meant for the Member Rep.\n\nPlease let me know if you have any questions.\n\nThank you,'
  },
  {
    id: 'member_manually_added',
    match: () => isManuallyAdded,
    subject: 'Manual Add Alert: Ticket #{{ticket_number}} - {{station_codes}}',
    body: 'Hello {{rep_name}},\n\nPlease review the email below from one of our agents for reference. The station code {{station_codes}} has been manually added to ticket# {{ticket_number}} at the request of the excavator.\n\nIf you need to update your Area of Interest, please visit the Damage Prevention Portal using the link below.\n\nCA DPP Login Page - https://appsca.undergroundservicealert.org/pcadmin/Account/Login?returnUrl=%2Fpcadmin%2FOperations - The Damage Prevention Portal is where you can manage your mapping, contact info, and ticket delivery.\n\nArea of Interest (AOI) can be found under Settings - OneCallAccess and clicking on your Station Code, then clicking on Area of Interest.\nHere is a video that goes into more detail: How to manage your Area of Interest - https://www.youtube.com/watch?v=KZzHnITi-3Q&feature=youtu.be\n\nThank you,'
  },
  {
    id: 'general',
    match: () => true,
    subject: 'DPS Alert: Ticket #{{ticket_number}} - {{station_codes}}',
    body: '{{rep_name}}, please review the form below and take appropriate action.\n\nTicket Number: {{ticket_number}}\nStation Code(s): {{station_codes}}\nState(s): {{states}}\nIssue Type: {{issue_type}}\n\nAdditional Notes:\n{{notes}}\n\nThank you,'
  }
];

const template = templates.find(t => t.match());

return [{
  json: {
    ...data,
    template: {
      id: template.id,
      subject_template: template.subject,
      body_template: template.body
    }
  }
}];

const data = $input.first().json;
return [{
  json: {
    status: 'EXCEPTION - ALL CODES UNMATCHED',
    exception_type: 'unknown_station_code',
    exception_reason: `Unknown station code(s): ${data.routing.unmatched_codes.join(', ')}`,
    input_data: {
      alert_id: data.alert_id,
      ticket_number: data.ticket_number,
      station_codes: data.member_codes,
      state: data.states
    }
  }
}];

const data = $input.first().json;
const recipients = data.routing.recipients;

return recipients.map(recipient => ({
  json: {
    ...data,
    current_recipient: recipient,
    station_codes_for_recipient: recipient.station_codes.join(', ')
  }
}));

const data = $input.first().json;
const template = data.template;
const recipient = data.current_recipient;

const CC_RECIPIENTS = [
  'trevor.harris@usan.org',
  'centeroperations@usanorth811.org',
  'germain.suess@usan.org'
];

const SIGNATURE = `\n\nChristian Olesen\nMember Services Representative\nUSAN - Underground Service Alert Network\nmemberservices@usan.org`;

function render(tmpl, vars) {
  let result = tmpl;
  for (const [key, value] of Object.entries(vars)) {
    result = result.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value || '');
  }
  return result;
}

const vars = {
  rep_name: recipient.rep_name,
  rep_email: recipient.rep_email,
  ticket_number: data.ticket_number,
  station_codes: recipient.station_codes.join(', '),
  all_station_codes: data.member_codes.join(', '),
  states: data.states.join(', '),
  notes: data.notes,
  customer_name: data.customer_name,
  alert_id: data.alert_id,
  issue_type: data.issue_type
};

const renderedBody = render(template.body_template, vars) + SIGNATURE;

return [{
  json: {
    email_number: $itemIndex + 1,
    status: 'DRAFT EMAIL PREVIEW',
    to: recipient.rep_email,
    to_name: recipient.rep_name,
    cc: CC_RECIPIENTS,
    subject: render(template.subject_template, vars),
    body: renderedBody,
    template_used: template.id,
    station_codes: recipient.station_codes,
    input_summary: {
      alert_id: data.alert_id,
      ticket_number: data.ticket_number,
      state: data.states.join(', '),
      issue_type: data.issue_type
    }
  }
}];

const items = $input.all();
const emails = items.map((item, idx) => item.json);

const summary = {
  total_emails_generated: emails.length,
  emails: emails.map(e => ({
    email_num: e.email_number,
    to: `${e.to_name} <${e.to}>`,
    cc: e.cc.join(', '),
    subject: e.subject,
    template: e.template_used,
    station_codes: e.station_codes.join(', '),
    body_preview: e.body.substring(0, 300) + '...'
  }))
};

return [{ json: summary }];
